static boolean isSimpleNumber(String s) {
    if (s == null || s.isEmpty()) return false;
    int len = s.length();
    int start = 0;
    // Handle negative numbers
    if (s.charAt(0) == '-') {
        if (len == 1) return false; // not valid if only a negative sign
        start = 1;
    }
    // Handle decimal numbers
    boolean hasDecimalPoint = false;
    for (int index = start; index < len; index++) {
        char c = s.charAt(index);
        if (c == '.') {
            if (hasDecimalPoint) return false; // more than one decimal point
            hasDecimalPoint = true;
            continue;
        }
        if (c < '0' || c > '9') {
            return false;
        }
    }
    // Check leading zero for integers or invalid empty decimal
    if (!hasDecimalPoint && len > start + 1 && s.charAt(start) == '0') {
        return false;
    }
    return true;
}

